// ============================================================
// Central Grants Description Backfill
// ------------------------------------------------------------
// Sweeps every row in central_grants whose description is NULL,
// empty, or shorter than THIN_LIMIT chars and asks the enrich
// webhook (the same one the main fetch pipeline uses) to improve
// it. Writes back only when the returned description is strictly
// longer than what's already stored, so re-running this workflow
// can never regress a description and picks up whatever failed
// last time.
//
// Safe by default: DRY_RUN=true prints the counts without mutating.
// Flip DRY_RUN to false once you've confirmed the numbers.
//
// Scope: every thin central_grants row (no org filter). Grants
// stay where they are - this only edits the description column
// in place. Org-level pipelines are untouched.
// ============================================================

const DRY_RUN     = true;     // <-- flip to false to actually run
const THIN_LIMIT  = 200;      // matches enrich workflow's threshold
const PAGE_SIZE   = 1000;     // Supabase pagination page
const CONCURRENCY = 10;       // parallel enrich calls (same as main fetch)
const MAX_GRANTS  = null;     // optional safety cap (e.g. 200 for first real run)

const SUPABASE_URL = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZndWRobGNrdHNzdHdweHd0d3p6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDk2NjA5NSwiZXhwIjoyMDg2NTQyMDk1fQ.lDXOCM7CStNfF0G-ZENg5x1dyQ0ytXHGtJ8DjQNd03I';
const ENRICH_URL  = 'https://n8n.thebrownmine.com/webhook/enrich-grant-description';

const helpers = this.helpers;
const supaHeaders = {
  'apikey':        SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY,
  'Content-Type':  'application/json',
};

// PostgREST can't filter by `length(column)`, so we paginate the
// whole catalog and filter thin rows in JS. ~6-10k rows is fine.
async function fetchAllCentralGrants() {
  const all = [];
  let offset = 0;
  const selectCols = 'id,title,funder_name,source,source_url,description,first_seen_at';
  while (true) {
    const rows = await helpers.httpRequest({
      method:  'GET',
      url:     SUPABASE_URL + '/central_grants?select=' + selectCols + '&order=first_seen_at.asc',
      headers: Object.assign({}, supaHeaders, {
        'Range-Unit': 'items',
        'Range':      offset + '-' + (offset + PAGE_SIZE - 1),
      }),
      json: true,
    });
    if (!Array.isArray(rows) || rows.length === 0) break;
    all.push.apply(all, rows);
    if (rows.length < PAGE_SIZE) break;
    offset += PAGE_SIZE;
  }
  return all;
}

async function enrichGrant(g) {
  try {
    const resp = await helpers.httpRequest({
      method:  'POST',
      url:     ENRICH_URL,
      headers: { 'Content-Type': 'application/json' },
      body:    JSON.stringify({
        title:       g.title || '',
        funder_name: g.funder_name || '',
        source_url:  g.source_url || '',
        description: g.description || '',
      }),
      json:    true,
      timeout: 90000,
    });
    const next = (resp && resp.description) || '';
    const enriched = !!(resp && resp.enriched);
    const source   = (resp && resp.source) || 'original';
    return { ok: true, description: next, enriched: enriched, source: source };
  } catch (e) {
    return { ok: false, message: String(e.message || e).slice(0, 400) };
  }
}

async function patchDescription(id, description) {
  if (DRY_RUN) return { ok: true };
  try {
    await helpers.httpRequest({
      method:  'PATCH',
      url:     SUPABASE_URL + '/central_grants?id=eq.' + encodeURIComponent(id),
      headers: Object.assign({}, supaHeaders, { 'Prefer': 'return=minimal' }),
      body:    JSON.stringify({ description: description }),
    });
    return { ok: true };
  } catch (e) {
    return { ok: false, message: String(e.message || e).slice(0, 400) };
  }
}

// -------------------- main --------------------
const all = await fetchAllCentralGrants();
let thin = all.filter(function (g) { return (g.description || '').length < THIN_LIMIT; });
if (MAX_GRANTS && thin.length > MAX_GRANTS) thin = thin.slice(0, MAX_GRANTS);

// Counters
let enrichedCount  = 0; // enrich webhook returned a longer description
let writtenCount   = 0; // we actually PATCHed central_grants (= enrichedCount when not DRY_RUN)
let unchangedCount = 0; // enrich returned same/shorter text - left as-is
let failedCount    = 0; // enrich call errored out
const writeErrors  = [];
const enrichErrors = [];
const bySource = {}; // source -> { scanned, enriched, unchanged, failed }

function bumpSource(source, field) {
  const key = source || 'unknown';
  const s = bySource[key] = bySource[key] || { scanned: 0, enriched: 0, unchanged: 0, failed: 0 };
  s[field]++;
}

for (let i = 0; i < thin.length; i += CONCURRENCY) {
  const slice = thin.slice(i, i + CONCURRENCY);
  const results = await Promise.all(slice.map(async function (g) {
    bumpSource(g.source, 'scanned');
    const r = await enrichGrant(g);
    return { grant: g, result: r };
  }));

  for (let j = 0; j < results.length; j++) {
    const g = results[j].grant;
    const r = results[j].result;
    if (!r.ok) {
      failedCount++;
      bumpSource(g.source, 'failed');
      if (enrichErrors.length < 20) enrichErrors.push({ id: g.id, message: r.message });
      continue;
    }
    const existingLen = (g.description || '').length;
    const nextLen     = (r.description || '').length;
    if (nextLen > existingLen && nextLen >= 1) {
      enrichedCount++;
      bumpSource(g.source, 'enriched');
      const patched = await patchDescription(g.id, r.description);
      if (patched.ok) {
        if (!DRY_RUN) writtenCount++;
      } else {
        if (writeErrors.length < 20) writeErrors.push({ id: g.id, message: patched.message });
      }
    } else {
      unchangedCount++;
      bumpSource(g.source, 'unchanged');
    }
  }
}

return [{
  json: {
    dry_run:         DRY_RUN,
    total_scanned:   all.length,
    thin_found:      thin.length,
    enriched:        enrichedCount,
    written:         writtenCount,
    unchanged:       unchangedCount,
    failed:          failedCount,
    thin_limit:      THIN_LIMIT,
    concurrency:     CONCURRENCY,
    max_grants_cap:  MAX_GRANTS,
    by_source:       bySource,
    errors: {
      enrich: enrichErrors,
      write:  writeErrors,
    },
  },
}];
